const attachments = $json.attachments || []
const pdf = attachments.find(a =>
  (a.name || '').toLowerCase().endsWith('.pdf') ||
  a.contentType === 'application/pdf'
)

if (!pdf || !pdf.contentBytes) {
  return [{ json: { hasPdf: false } }]
}

const fileName = `${Date.now()}_${(pdf.name || 'invoice.pdf').replace(/[^a-zA-Z0-9._-]/g, '_')}`

return [{
  json: {
    hasPdf: true,
    pdfBase64: pdf.contentBytes,
    fileName,
    emailSubject: $json.subject || '',
    emailFrom: $json.from?.emailAddress?.address || ''
  },
  binary: {
    data: {
      data: pdf.contentBytes,
      mimeType: 'application/pdf',
      fileName
    }
  }
}]

const pdfBase64 = $json.pdfBase64

const body = {
  contents: [{ parts: [
    { inline_data: { mime_type: 'application/pdf', data: pdfBase64 } },
    { text: 'Ist dieses Dokument eine Rechnung, ein Kassenbon oder eine Quittung? Antworte NUR mit JSON: {"is_invoice": true} oder {"is_invoice": false}. Lieferscheine, Angebote, Newsletter, Bestellbestätigungen ohne Zahlungsaufforderung, Verträge und Mahnungen sind KEINE Rechnungen.' }
  ]}],
  generationConfig: {
    response_mime_type: 'application/json',
    response_schema: {
      type: 'OBJECT',
      properties: { is_invoice: { type: 'BOOLEAN' } },
      required: ['is_invoice']
    }
  }
}

return [{
  json: {
    checkBody: JSON.stringify(body),
    pdfBase64: $json.pdfBase64,
    fileName: $json.fileName,
    emailSubject: $json.emailSubject,
    emailFrom: $json.emailFrom
  },
  binary: $input.first().binary
}]

const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text
let isInvoice = false
try {
  const parsed = typeof rawText === 'string' ? JSON.parse(rawText) : (rawText ?? {})
  isInvoice = parsed.is_invoice === true
} catch {}

const prev = $('Rechnungsprüfung vorbereiten').first().json

return [{
  json: {
    isInvoice,
    pdfBase64:    prev.pdfBase64,
    fileName:     prev.fileName,
    emailSubject: prev.emailSubject,
    emailFrom:    prev.emailFrom
  },
  binary: $('Rechnungsprüfung vorbereiten').first().binary
}]

// Binary aus PDF extrahieren wiederherstellen (geht durch HTTP-Nodes verloren)
const pdfBinary = $('PDF extrahieren').first().binary

return [{
  json: $input.first().json,
  binary: pdfBinary
}]

const all = $input.all()
const kategorien = all.map(item => ({
  wert: item.json.wert,
  beschreibung: item.json.beschreibung
}))

const prev = $('Rechnungsprüfung vorbereiten').first().json

return [{
  json: {
    kategorien,
    pdfBase64: prev.pdfBase64,
    fileName:  prev.fileName
  }
}]

const CARD_MAP = {
  '1380': 'spesen_philipp_1380',
  '0744': 'spesen_philipp_0744',
  '6362': 'firmenkarte_6362',
  '0660': 'firmenkarte_0660'
}

function normalizeDate(raw) {
  if (!raw) return null
  const s = String(raw).trim()
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s
  if (s.includes('.')) {
    const [d, m, y] = s.split('.')
    if (d && m && y) return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`
  }
  const p = new Date(s)
  return isNaN(p.getTime()) ? null : p.toISOString().split('T')[0]
}

const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text
let ocr = typeof rawText === 'string' ? JSON.parse(rawText) : (rawText ?? {})

// Proforma → alle Steuerfelder null
if (ocr.is_proforma) {
  ocr = { ...ocr, tax_rate: null, tax_amount_10: null, tax_amount_20: null, net_amount_10: null, net_amount_20: null }
}
// 19% → 20% (Österreich)
if (ocr.tax_rate === 19) ocr = { ...ocr, tax_rate: 20 }
// Kein Steuersatz aber Betrag → Standard 20%
if (!ocr.is_proforma && !ocr.tax_rate && ocr.net_amount) ocr = { ...ocr, tax_rate: 20 }

// effectiveNetto: Aufschlüsselung bevorzugen
const n10 = ocr.net_amount_10 ?? 0
const n20 = ocr.net_amount_20 ?? 0
const n0  = ocr.net_amount_0  ?? 0
const sum = n10 + n20 + n0
const netto = sum > 0 ? Math.round(sum * 100) / 100 : (ocr.net_amount ?? 0)

const digits = ocr.card_last_four ? String(ocr.card_last_four).trim() : null
const karte  = digits ? (CARD_MAP[digits] ?? 'sonstige') : null

const pdfUrl = $('Gemini Request vorbereiten').first().json.pdfUrl

return [{
  json: {
    rechnungsnr:    ocr.invoice_number?.trim() || `EMAIL-${Date.now()}`,
    rechnungsdatum: normalizeDate(ocr.invoice_date) || null,
    faelligkeit:    normalizeDate(ocr.due_date)     || null,
    betrag:         netto,
    ust_satz:       ocr.is_proforma ? 0 : (ocr.tax_rate ?? 20),
    rechnungstyp:   ocr.invoice_type || null,
    betrag_10:      ocr.net_amount_10 ?? null,
    betrag_20:      ocr.net_amount_20 ?? null,
    betrag_0:       ocr.net_amount_0  ?? null,
    mwst_10:        ocr.tax_amount_10 ?? null,
    mwst_20:        ocr.tax_amount_20 ?? null,
    karte:          karte,
    pdf_url:        pdfUrl,
    status:         'eingegangen',
    ocr_json:       ocr,
    supplier_name:  ocr.supplier_name || 'Unbekannter Lieferant'
  }
}]

const SUPABASE_URL = $env.SUPABASE_URL
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY

const headers = {
  'apikey':        SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type':  'application/json',
  'Prefer':        'return=representation'
}

const supplierName = $json.supplier_name

// 1. Lieferant suchen oder anlegen
let lieferantId = null
try {
  const found = await $helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/lieferanten?name=ilike.${encodeURIComponent(supplierName)}&select=id&limit=1`,
    headers
  })
  if (found.length > 0) {
    lieferantId = found[0].id
  } else {
    const created = await $helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/lieferanten`,
      headers,
      body: JSON.stringify({ name: supplierName })
    })
    lieferantId = created[0]?.id || null
  }
} catch (e) {
  console.error('Lieferant Fehler:', e.message)
}

// 2. Rechnung einfügen
const rechnung = {
  rechnungsnr:    $json.rechnungsnr,
  rechnungsdatum: $json.rechnungsdatum,
  faelligkeit:    $json.faelligkeit,
  betrag:         $json.betrag,
  ust_satz:       $json.ust_satz,
  rechnungstyp:   $json.rechnungstyp,
  betrag_10:      $json.betrag_10,
  betrag_20:      $json.betrag_20,
  betrag_0:       $json.betrag_0,
  mwst_10:        $json.mwst_10,
  mwst_20:        $json.mwst_20,
  karte:          $json.karte,
  pdf_url:        $json.pdf_url,
  status:         'eingegangen',
  lieferant_id:   lieferantId,
  ocr_json:       $json.ocr_json
}

const inserted = await $helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/rechnungen`,
  headers,
  body: JSON.stringify(rechnung)
})

return [{
  json: {
    success:     true,
    rechnung_id: inserted[0]?.id,
    rechnungsnr: $json.rechnungsnr,
    supplier:    supplierName,
    betrag:      $json.betrag
  }
}]
